def flatten(lst):
    flat = []
    for item in lst:
        if isinstance(item, list):
            flat.extend(flatten(item))
        else:
            flat.append(item)
    return flat
```

```python
def chunk_string(s, n):
    if not s or n <= 0:
        return []

    result = []
    for i in range(0, len(s) - (n - 1), n):
        result.append(s[i:i+n])

    return result
```

```python
def decode_ranges(spec):
    """Decode a range string into a list of integers."""
    result = []
    for part in spec.split(','):
        if '-' in part:
            start, end = map(int, part.split('-'))
            result.extend(range(start, end + 1))
        else:
            result.append(int(part))
    return result
```

```python
def nest_by_dots(flat):
    """Convert a dictionary with dotted keys into a nested dictionary."""
    result = {}
    for key, value in flat.items():
        if '.' in key:
            parts = key.split('.')
            current = result
            for part in parts[:-1]:  # Stop before the last dot
                if part not in current:
                    current[part] = {}
                current = current[part]
            current[parts[-1]] = value
        else:
            result[key] = value
    return result
```
